## 🔩 Immediate Code — Execution Scheduler (PRODUCTION)

### `execution_scheduler.h`

```cpp
#pragma once
#include <windows.h>
#include <atomic>
#include <thread>
#include <mutex>
#include <unordered_map>
#include <functional>
#include <chrono>

namespace RawrXD {

using TaskId = uint64_t;

enum class TaskState {
    Pending,
    Running,
    Completed,
    Cancelled,
    TimedOut,
    Killed
};

enum class TaskType {
    TerminalCommand,
    ToolInvocation,
    AgentAction,
    BackgroundJob
};

struct Task {
    TaskId id;
    TaskType type;
    uint64_t timeout_ms;
    std::atomic<TaskState> state;
    HANDLE process;
    std::chrono::steady_clock::time_point start;
    std::function<void()> cancel;
};

class ExecutionScheduler {
public:
    static ExecutionScheduler& Instance();

    TaskId submit(Task&& task);
    bool cancel(TaskId id);
    void shutdown();

private:
    ExecutionScheduler();
    ~ExecutionScheduler();

    void watchdogLoop();
    void killTask(Task& task);

    std::atomic<bool> m_running;
    std::thread m_watchdog;
    std::mutex m_lock;
    std::unordered_map<TaskId, Task> m_tasks;
    TaskId m_nextId;
};

}
```

---

### `execution_scheduler.cpp`

```cpp
#include "execution_scheduler.h"

using namespace RawrXD;

ExecutionScheduler& ExecutionScheduler::Instance() {
    static ExecutionScheduler inst;
    return inst;
}

ExecutionScheduler::ExecutionScheduler()
    : m_running(true), m_nextId(1) {
    m_watchdog = std::thread(&ExecutionScheduler::watchdogLoop, this);
}

ExecutionScheduler::~ExecutionScheduler() {
    shutdown();
}

TaskId ExecutionScheduler::submit(Task&& task) {
    std::lock_guard<std::mutex> g(m_lock);

    task.id = m_nextId++;
    task.state = TaskState::Pending;
    task.start = std::chrono::steady_clock::now();

    m_tasks.emplace(task.id, std::move(task));
    return task.id;
}

bool ExecutionScheduler::cancel(TaskId id) {
    std::lock_guard<std::mutex> g(m_lock);
    auto it = m_tasks.find(id);
    if (it == m_tasks.end())
        return false;

    auto& t = it->second;
    if (t.state == TaskState::Running && t.cancel) {
        t.cancel();
        t.state = TaskState::Cancelled;
        return true;
    }
    return false;
}

void ExecutionScheduler::killTask(Task& task) {
    if (task.process) {
        TerminateProcess(task.process, 1);
        CloseHandle(task.process);
        task.process = nullptr;
    }
    task.state = TaskState::Killed;
}

void ExecutionScheduler::watchdogLoop() {
    while (m_running) {
        {
            std::lock_guard<std::mutex> g(m_lock);
            auto now = std::chrono::steady_clock::now();

            for (auto& [id, task] : m_tasks) {
                if (task.state != TaskState::Running)
                    continue;

                auto elapsed =
                    std::chrono::duration_cast<std::chrono::milliseconds>(
                        now - task.start).count();

                if (elapsed > task.timeout_ms) {
                    killTask(task);
                }
            }
        }
        Sleep(50);
    }
}

void ExecutionScheduler::shutdown() {
    m_running = false;
    if (m_watchdog.joinable())
        m_watchdog.join();
}
