### **The Technical Execution — `Win32_TerminalWatchdog**`

This response provides the low-level **C++20/Win32** implementation required to multitask terminal prompts without blocking the Agent's reasoning engine.

#### **The Non-Blocking Terminal Wrapper**

We use `CreateProcess` with `PeekNamedPipe` to ensure the "Read" operation never stalls the main thread.

```cpp
// src/core/terminal_watchdog.h
#pragma once
#include <windows.h>
#include <string>
#include <atomic>

struct TermTask {
    HANDLE hProcess;
    HANDLE hReadPipe;
    DWORD startTime;
    std::string outputBuffer;
    bool isAlive;
};

class TerminalWatchdog {
public:
    // Non-blocking start
    static TermTask* Spawn(const std::wstring& cmd) {
        HANDLE hRead, hWrite;
        SECURITY_ATTRIBUTES sa = { sizeof(sa), NULL, TRUE };
        CreatePipe(&hRead, &hWrite, &sa, 0);
        SetHandleInformation(hRead, HANDLE_FLAG_INHERIT, 0);

        STARTUPINFOW si = { sizeof(si) };
        si.dwFlags = STARTF_USESTDHANDLES | STARTF_USESHOWWINDOW;
        si.hStdOutput = hWrite;
        si.hStdError = hWrite;
        si.wShowWindow = SW_HIDE;

        PROCESS_INFORMATION pi = { 0 };
        if (CreateProcessW(NULL, (LPWSTR)cmd.c_str(), NULL, NULL, TRUE, 0, NULL, NULL, &si, &pi)) {
            CloseHandle(hWrite); // Close write end in parent
            return new TermTask{ pi.hProcess, hRead, GetTickCount(), "", true };
        }
        return nullptr;
    }

    // Polling function for the Agentic Loop
    static void Poll(TermTask* task, DWORD timeout_ms = 3500) {
        if (!task || !task->isAlive) return;

        // 1. Check for Output (Non-blocking)
        DWORD avail = 0;
        if (PeekNamedPipe(task->hReadPipe, NULL, 0, NULL, &avail, NULL) && avail > 0) {
            char buf[1024];
            DWORD read;
            ReadFile(task->hReadPipe, buf, sizeof(buf)-1, &read, NULL);
            buf[read] = '\0';
            task->outputBuffer += buf;
        }

        // 2. Check for Completion or Hang
        DWORD wait = WaitForSingleObject(task->hProcess, 0);
        if (wait == WAIT_OBJECT_0) {
            task->isAlive = false;
        } else if (GetTickCount() - task->startTime > timeout_ms) {
            // 3. THE KILL SWITCH
            TerminateProcess(task->hProcess, 0xF471); // Custom exit code for "Hang"
            task->outputBuffer += "\n[SYSTEM: TIMEOUT - COMMAND TERMINATED]";
            task->isAlive = false;
        }
    }
};

