#pragma once
#include <windows.h>
#include <atomic>
#include <thread>
#include <mutex>
#include <unordered_map>
#include <functional>
#include <chrono>

namespace RawrXD {

using TaskId = uint64_t;

enum class TaskState {
    Pending,
    Running,
    Completed,
    Cancelled,
    TimedOut,
    Killed
};

enum class TaskType {
    TerminalCommand,
    ToolInvocation,
    AgentAction,
    BackgroundJob
};

struct Task {
    TaskId id;
    TaskType type;
    uint64_t timeout_ms;
    std::atomic<TaskState> state;
    HANDLE process;
    std::chrono::steady_clock::time_point start;
    std::function<void()> cancel;
};

class ExecutionScheduler {
public:
    static ExecutionScheduler& Instance();

    TaskId submit(Task&& task);
    bool cancel(TaskId id);
    void shutdown();

private:
    ExecutionScheduler();
    ~ExecutionScheduler();

    void watchdogLoop();
    void killTask(Task& task);

    std::atomic<bool> m_running;
    std::thread m_watchdog;
    std::mutex m_lock;
    std::unordered_map<TaskId, Task> m_tasks;
    TaskId m_nextId;
};

}
```

