void AutonomousRepairAgent::OnDiagnosticsReceived(
    const std::string& uri, 
    const std::vector<LSPDiagnostic>& diagnostics) {
    
    // Filter for actionable errors only (ignore warnings)
    for (const auto& diag : diagnostics) {
        if (diag.severity > 1) continue;  // 1=Error, 2=Warning, 3=Info, 4=Hint
        
        auto candidate = RepairCandidate{};
        candidate.filePath = std::filesystem::path(uri).wstring();
        candidate.diagnosticRange = diag.range;
        candidate.diagnosticMessage = diag.message;
        candidate.strategy = ClassifyDiagnostic(diag);
        
        // Generate AI suggestion using Multi-Response
        auto& mre = MultiResponseEngine::Instance();
        auto responses = mre.GenerateResponses(
            GeneratePrompt(candidate),
            3,  // 3 different strategies
            ResponseStyle::Grounded  // Low temp for code fixes
        );
        
        // Pick highest confidence response
        if (!responses.empty()) {
            candidate.aiSuggestion = responses[0].content;
            candidate.confidenceScore = responses[0].confidence;
            
            // Generate diff
            std::stringstream diff;
            diff << "--- a/" << uri << "\n";
            diff << "+++ b/" << uri << "\n";
            diff << "@@ -" << diag.range.start.line << ",1 +" 
                 << diag.range.start.line << ",1 @@\n";
            diff << "-" << diag.sourceLine << "\n";
            diff << "+" << candidate.aiSuggestion << "\n";
            candidate.diffPatch = diff.str();
            
            // Decision: Auto-apply or queue for review?
            if (candidate.confidenceScore > m_autoThreshold && 
                !candidate.requiresApproval) {
                ExecuteRepairAsync(candidate);
            } else {
                // Send to UI for human approval
                PostMessageW(g_hMainWnd, WM_USER + 200, 
                           (WPARAM)new RepairCandidate(candidate), 0);
            }
        }
    }
}

RepairStrategy AutonomousRepairAgent::ClassifyDiagnostic(const LSPDiagnostic& diag) {
    const std::string& msg = diag.message;
    
    // Pattern matching for strategy selection
    if (msg.find("expected") != std::string::npos || 
        msg.find("missing") != std::string::npos ||
        msg.find("Unexpected") != std::string::npos) {
        return RepairStrategy::SyntaxFix;
    }
    if (msg.find("cannot convert") != std::string::npos ||
        msg.find("no matching function") != std::string::npos) {
        return RepairStrategy::TypeFix;
    }
    if (msg.find("undefined reference") != std::string::npos ||
        msg.find("linker") != std::string::npos) {
        return RepairStrategy::LinkFix;
    }
    if (msg.find("logic") != std::string::npos ||
        msg.find("algorithm") != std::string::npos) {
        return RepairStrategy::LogicFix;
    }
    return RepairStrategy::Unknown;
}

std::string AutonomousRepairAgent::GeneratePrompt(const RepairCandidate& candidate) {
    std::stringstream prompt;
    prompt << "You are an expert compiler error repair system.\n";
    prompt << "File: " << std::filesystem::path(candidate.filePath).filename().string() << "\n";
    prompt << "Error: " << candidate.diagnosticMessage << "\n";
    prompt << "Line: " << candidate.diagnosticRange.start.line << "\n";
    prompt << "Strategy: ";
    
    switch (candidate.strategy) {
        case RepairStrategy::SyntaxFix: 
            prompt << "Fix syntax only (brackets, semicolons, keywords)"; break;
        case RepairStrategy::TypeFix: 
            prompt << "Fix type mismatch (casts, overloads)"; break;
        case RepairStrategy::LinkFix: 
            prompt << "Fix linking (includes, extern declarations)"; break;
        default: 
            prompt << "General fix";
    }
    
    prompt << "\n\nProvide ONLY the corrected code line(s). No explanation.\n";
    prompt << "Context:\n```\n[LINE " << candidate.diagnosticRange.start.line << "]\n```\n";
    
    return prompt.str();
}

void AutonomousRepairAgent::ExecuteRepairAsync(const RepairCandidate& candidate) {
    // Git snapshot before mutation
    if (m_gitSnapshots) {
        git_repository* repo = nullptr;
