        std::string narrowPath(candidate.filePath.begin(), candidate.filePath.end());
        git_repository_open(&repo, m_repoRoot.string().c_str());
        git_repository_index(&index, repo);
        
        // Stage current state
        git_index_add_bypath(index, 
            std::filesystem::relative(candidate.filePath, m_repoRoot).string().c_str());
        git_index_write(index);
        
        // Create snapshot commit (WIP)
